using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time
    sort(edges.begin(), edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Find the maximum time
    long long max_time = 0;
    for (auto& e : edges) {
        if (e[2] > max_time) {
            max_time = e[2];
        }
    }

    // Binary search for the minimal t
    long long low = 0, high = max_time;
    long long answer = max_time;

    while (low <= high) {
        long long mid = (low + high) / 2;
        // Check if the number of components is >=k when edges with time >mid are present
        vector<vector<long long>> adj(n);
        for (auto& e : edges) {
            if (e[2] > mid) {
                adj[e[0]].push_back(e[1]);
                adj[e[1]].push_back(e[0]);
            }
        }
        vector<bool> visited(n, false);
        long long components = 0;
        for (long long i = 0; i < n; ++i) {
            if (!visited[i]) {
                ++components;
                queue<long long> q;
                q.push(i);
                visited[i] = true;
                while (!q.empty()) {
                    long long u = q.front();
                    q.pop();
                    for (long long v : adj[u]) {
                        if (!visited[v]) {
                            visited[v] = true;
                            q.push(v);
                        }
                    }
                }
            }
        }
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

