        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        long max_time = 0;
        for (long[] e : edges) {
            if (e[2] > max_time) {
                max_time = e[2];
            }
        }

        long low = 0, high = max_time;
        long answer = max_time;

        while (low <= high) {
