                        for (long v : adj.get((int)u)) {
                            if (!visited[v]) {
                                visited[v] = true;
                                q.add(v);
                            }
                        }
                    }
                }
            }
            if (components >= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }
}
